import React, { useState, useEffect, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import {
	Container,
	Box,
	Typography,
	Button,
	Card,
	CardContent,
	Chip,
	CircularProgress,
	Alert,
	Grid,
} from '@mui/material';
import { PlayArrow as StartIcon, AssignmentTurnedIn as TaskIcon } from '@mui/icons-material';
import { AuthContext } from '../context/AuthContext';
import api from '../api';
import KanbanBoard from '../components/KanbanBoard';

export default function EmployeeDashboard() {
	const navigate = useNavigate();
	const { user } = useContext(AuthContext);
	const [tasks, setTasks] = useState([]);
	const [loading, setLoading] = useState(true);
	const [error, setError] = useState('');
	const [updating, setUpdating] = useState(null);

	const fetchTasks = async () => {
		setLoading(true);
		try {
			const res = await api.get('/tasks');
			const body = res.data;
			const list = Array.isArray(body) ? body : (body.tasks ?? body.data ?? []);
			setTasks(list || []);
			setError('');
		} catch (err) {
			console.error('Failed to load tasks', err);
			setError('Failed to load tasks');
		} finally {
			setLoading(false);
		}
	};

	useEffect(() => {
		fetchTasks();
	}, []);

	const getTaskStats = () => {
		const myTasks = tasks.filter((t) => t.assigned_users?.some((u) => u.id === user?.id));
		return {
			pending: myTasks.filter((t) => t.status === 'pending').length,
			in_progress: myTasks.filter((t) => t.status === 'in_progress').length,
			completed: myTasks.filter((t) => t.status === 'completed').length,
		};
	};

	const getColumns = () => {
		const firstWith = tasks.find((t) => (t.progression_steps || []).length);
		if (firstWith) return firstWith.progression_steps.map((s) => ({ id: s.id, name: s.name }));
		return [
			{ id: null, name: 'To Do', key: 'pending' },
			{ id: null, name: 'In Progress', key: 'in_progress' },
			{ id: null, name: 'Done', key: 'completed' },
		];
	};

	const getTasksByColumn = () => {
		const map = {};
		const cols = getColumns();
		if (cols && cols[0] && cols[0].id != null) {
			cols.forEach((c) => (map[c.id] = []));
			tasks.forEach((task) => {
				const key = task.progression_step?.id ?? null;
				if (map[key]) map[key].push(task);
				else map[cols[0].id].push(task);
			});
			return map;
		}

		map['pending'] = tasks.filter((t) => t.status === 'pending');
		map['in_progress'] = tasks.filter((t) => t.status === 'in_progress');
		map['completed'] = tasks.filter((t) => t.status === 'completed');
		return map;
	};

	const handleMoveTask = async (taskId, info) => {
		try {
			const column = info.column;
			const isNumeric = String(column).match(/^[0-9]+$/);
			const payload = isNumeric ? { task_progression_step_id: column } : { status: column };
			await api.patch(`/tasks/${taskId}/status`, payload);
			fetchTasks();
		} catch (err) {
			console.error('Failed to move task', err);
		}
	};

	const resolveStepIndex = (task) => {
		const steps = task.progression_steps || [];
		if (!task.progression_step) return -1;
		return steps.findIndex((s) => String(s.id) === String(task.progression_step.id));
	};

	const getStatusMeta = (task) => {
		const mapping = {
			pending: { bg: '#FEF3C7', text: '#92400E' },
			in_progress: { bg: '#E0F2FE', text: '#0369A1' },
			completed: { bg: '#DCFCE7', text: '#065F46' },
		};
		return mapping[task.status] || { bg: '#E2E8F0', text: '#0F172A' };
	};

	const getStatusLabel = (task) => {
		if (task.progression_step) return task.progression_step.name;
		return task.status;
	};

	const updateTaskStatus = async (taskId, payload) => {
		setUpdating(taskId);
		try {
			await api.patch(`/tasks/${taskId}/status`, payload);
			await fetchTasks();
		} catch (err) {
			console.error('Failed to update task', err);
		} finally {
			setUpdating(null);
		}
	};

	const stats = getTaskStats();

	return (
		<Box sx={{ backgroundColor: '#F8FAFC', minHeight: 'calc(100vh - 64px)', py: 4 }}>
			<Container maxWidth="lg">
				<Box sx={{ mb: 4 }}>
					<Typography variant="h4" sx={{ fontWeight: 700, mb: 1 }}>
						My Tasks
					</Typography>
					<Typography variant="body2" sx={{ color: '#64748B' }}>
						Track and manage your assigned work
					</Typography>
				</Box>

				<Grid container spacing={3} sx={{ mb: 4 }}>
					{[
						{ label: 'Pending', value: stats.pending, color: '#F59E0B' },
						{ label: 'In Progress', value: stats.in_progress, color: '#06B6D4' },
						{ label: 'Completed', value: stats.completed, color: '#10B981' },
					].map((stat) => (
						<Grid item xs={12} sm={6} md={3} key={stat.label}>
							<Card sx={{ border: '1px solid #E2E8F0', borderLeft: `4px solid ${stat.color}` }}>
								<CardContent sx={{ textAlign: 'center' }}>
									<Typography variant="h3" sx={{ color: stat.color, fontWeight: 700, mb: 1 }}>
										{stat.value}
									</Typography>
									<Typography variant="body2" sx={{ color: '#64748B' }}>
										{stat.label}
									</Typography>
								</CardContent>
							</Card>
						</Grid>
					))}
				</Grid>

				{error && (
					<Alert severity="error" sx={{ mb: 3, borderRadius: 2 }}>
						{error}
					</Alert>
				)}

				{loading ? (
					<Box sx={{ display: 'flex', justifyContent: 'center', py: 6 }}>
						<CircularProgress />
					</Box>
				) : tasks.length === 0 ? (
					<Card sx={{ backgroundColor: '#fff', border: '1px solid #E2E8F0', textAlign: 'center', py: 6 }}>
						<TaskIcon sx={{ fontSize: 48, color: '#CBD5E1', mb: 2 }} />
						<Typography variant="h6" sx={{ color: '#0F172A', mb: 1 }}>
							No tasks assigned yet
						</Typography>
						<Typography variant="body2" sx={{ color: '#64748B' }}>
							Check back soon for new assignments from your team lead.
						</Typography>
					</Card>
				) : (
					<Box>
						<KanbanBoard
							columns={getColumns()}
							tasksByColumn={getTasksByColumn()}
							currentUser={user}
							canDragTask={(task, currentUser) => task.assigned_users?.some((u) => u.id === currentUser?.id)}
							onMoveTask={handleMoveTask}
						/>

						<Grid container spacing={3} sx={{ mt: 4 }}>
							{tasks.map((task) => {
								const statusColor = getStatusMeta(task);
								const steps = task.progression_steps || [];
								const stepIndex = resolveStepIndex(task);
								const lastIndex = steps.length - 1;
								const isCompleted = stepIndex === lastIndex && lastIndex >= 0;
								const nextStep = steps[stepIndex + 1];

								return (
									<Grid item xs={12} sm={6} md={4} key={task.id}>
										<Card sx={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
											<CardContent sx={{ flex: 1 }}>
												<Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', mb: 2 }}>
													<Typography variant="h6" sx={{ fontWeight: 600, color: '#0F172A', flex: 1, mr: 1 }}>
														{task.title}
													</Typography>
													<Chip label={getStatusLabel(task)} size="small" sx={{ backgroundColor: statusColor.bg, color: statusColor.text }} />
												</Box>
												<Typography variant="body2" sx={{ color: '#64748B', mb: 2 }}>{task.description}</Typography>
												<Typography variant="caption" sx={{ color: '#94A3B8', display: 'block' }}>📅 Created: {new Date(task.created_at).toLocaleDateString('en-US')}</Typography>
											</CardContent>
											<Box sx={{ p: 2, borderTop: '1px solid #E2E8F0', display: 'flex', gap: 1 }}>
												{!isCompleted && nextStep && (
													<Button size="small" variant="contained" startIcon={<StartIcon />} onClick={() => updateTaskStatus(task.id, nextStep.id ? { task_progression_step_id: nextStep.id } : { status: nextStep.key })} disabled={updating === task.id} sx={{ flex: 1 }}>
														Move to {nextStep.name}
													</Button>
												)}
												{isCompleted && (
													<Box sx={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
														<Chip label={`✓ ${getStatusLabel(task)}`} sx={{ backgroundColor: '#DCFCE7', color: '#10B981' }} />
													</Box>
												)}
											</Box>
										</Card>
									</Grid>
								);
							})}
						</Grid>
					</Box>
				)}
			</Container>
		</Box>
	);
}
